/**
 * @param {number} n
 * @param {number[][]} edges
 * @return {number}
 */
function solve(n, edges) {
    // DSU structure initialization
    // parent[i]: parent of node i
    const parent = Array(n).fill(0).map((_, i) => i);
    // parity[i]: parity of path weight from node i to its current root (mod 2)
    const parity = Array(n).fill(0); 

    /**
     * Finds the root of node i and performs path compression, updating parity along the way.
     * @param {number} i 
     * @returns {number} The root of the component containing i.
     */
    const find = (i) => {
        if (parent[i] === i) {
            return i;
        }

        // Recursively find the ultimate root
        const root = find(parent[i]);

        // Update parity[i]: 
        // The new parity is the sum (mod 2) of the old parity[i] (i -> old_parent[i]) 
        // and the parity[old_parent[i]] (old_parent[i] -> root).
        parity[i] = (parity[i] + parity[parent[i]]) % 2;

        // Path compression
        parent[i] = root;

        return root;
    };

    let added_edges_count = 0;

    for (const edge of edges) {
        const [u, v, w] = edge;

        // Find roots and ensure parities are relative to the current roots
        const rootU = find(u);
        const rootV = find(v);

        // pU = P(u -> rootU), pV = P(v -> rootV)
        const pU = parity[u]; 
        const pV = parity[v];

        if (rootU === rootV) {
            // Case 1: Cycle formed. Check cycle parity.
            // Path u -> v via tree has parity pU + pV (mod 2).
            // Cycle parity = (pU + pV + w) mod 2.

            const cycle_parity = (pU + pV + w) % 2;

            if (cycle_parity === 0) {
                // Even cycle, accept the edge
                added_edges_count++;
            }
            // If cycle_parity === 1, reject the edge.

        } else {
            // Case 2: Different components. Merge them (Union).

            // Merge rootU into rootV
            parent[rootU] = rootV;

            // Calculate parity[rootU] = P(rootU -> rootV) mod 2
            // Path: rootU -> u --w--> v -> rootV
            // P(rootU -> u) = pU
            // P(v -> rootV) = pV
            // P(rootU -> rootV) = pU + w + pV (mod 2)

            parity[rootU] = (pU + w + pV) % 2;

            added_edges_count++;
        }
    }

    return added_edges_count;
}

